    public int damageUpgradeCost = 50;

    public int healthUpgradeCost = 100;

    public void TakeDamage(int amount)
    {
        health -= amount;
        if (health <= 0)
        {
            // Game over logic
        }
    }

    public void PurchaseDamageUpgrade()
    {
        if (currency >= damageUpgradeCost)
        {
